  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) break;

    // z = ((z^2 + c - 1) / (2z + c - 2))^2
    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;

    final numx = z2x + cx - 1.0;
    final numy = z2y + cy;
    final denx = 2.0 * zx + cx - 2.0;
    final deny = 2.0 * zy + cy;

