  if (it >= iterations) return _insideColor;
  final mag2 = zx * zx + zy * zy;
  final t = _smoothEscape(it: it, iterations: iterations, mag2: mag2 + 1.0);
  return _palette(t);
}

(double r, double g, double b) _cpu_magnet_type_2(
