  'gingerbreadman': _proxyFromColor('gingerbreadman'),
  'peter_de_jong': _proxyFromColor('peter_de_jong'),
  'arnold_cat': _proxyFromColor('arnold_cat'),
  'arneodo': _proxyFromColor('arneodo'),
  'halvorsen': _proxyFromColor('halvorsen'),
  'moore_spiegel': _proxyFromColor('moore_spiegel'),
  'genesio_tesi': _proxyFromColor('genesio_tesi'),
  'bouali': _proxyFromColor('bouali'),
  'buffalo_julia': _proxyFromColor('buffalo_julia'),
  'perpendicular_julia': _proxyFromColor('perpendicular_julia'),
  'cosine_mandelbrot': _proxyFromColor('cosine_mandelbrot'),
  'lyapunov': _proxyFromColor('lyapunov'),
  'logistic_lyapunov': _proxyFromColor('logistic_lyapunov'),
  'feigenbaum': _proxyFromColor('feigenbaum'),
  'buddhabrot_approx': _proxyFromColor('buddhabrot_approx'),
  'anti_buddhabrot': _proxyFromColor('anti_buddhabrot'),
  'wolfram_rule30': _proxyFromColor('wolfram_rule30'),
  'turmite': _proxyFromColor('turmite'),
  'eden_growth': _proxyFromColor('eden_growth'),
  'moore_curve': _proxyFromColor('moore_curve'),
  'spider_x': _proxyFromColor('spider_x'),
  'hat_monotile': _proxyFromColor('hat_monotile'),
};

CpuIterator proxyIteratorForModule(String moduleId) {
  return cpuIteratorsByModuleId[moduleId] ?? _proxyFromColor(moduleId);
}

CpuIterator _proxyFromColor(String moduleId) {
  final seed = _fnv1a32(moduleId);
  return (x, y, iterations, bailout, juliaC) {
    final f = cpuFormulaForModuleId(moduleId);
    final c = f(x, y, iterations, bailout, juliaC);

    // Proxy scalar from color.
    final lum =
        (0.2126 * c.$1 + 0.7152 * c.$2 + 0.0722 * c.$3).clamp(0.0, 255.0);
    var it = ((lum / 255.0) * iterations).floor().clamp(0, iterations);

    // If the CPU formula returns a very flat color field (common for "synthetic"
    // placeholder modules), luminance quantization can collapse to a constant.
    // Mix in a tiny, deterministic spatial hash so audits still detect structure.
    final xi = (x * 1e6).round();
    final yi = (y * 1e6).round();
    final h = _mix32(seed ^ (xi * 374761393) ^ (yi * 668265263));
    it = (it ^ (h & 0x0F)).clamp(0, iterations);

    return CpuIteratorResult(
        it: it, smoothIt: it.toDouble(), escaped: it < iterations);
  };
}

CpuIteratorResult _iterMandelbrot(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = 2.0 * zx * zy + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterBurningShip(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final ax = zx.abs();
    final ay = zy.abs();
    final zx2 = ax * ax;
    final zy2 = ay * ay;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = 2.0 * ax * ay + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterTricorn(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = -2.0 * zx * zy + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterJulia(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = x;
  double zy = y;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + juliaC.x;
    final ny = 2.0 * zx * zy + juliaC.y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterMultibrot4(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z4x = z2x * z2x - z2y * z2y;
    final z4y = 2.0 * z2x * z2y;
    zx = z4x + x;
    zy = z4y + y;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterMultibrot5(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z4x = z2x * z2x - z2y * z2y;
    final z4y = 2.0 * z2x * z2y;
    final z5x = z4x * zx - z4y * zy;
    final z5y = z4x * zy + z4y * zx;
    zx = z5x + x;
    zy = z5y + y;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterPhoenix(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Stable CPU default for p matches phoenix module default.
  const p = -0.5;

  double zx = x;
  double zy = y;
  double zPrevX = 0.0;
  double zPrevY = 0.0;

  final cx = juliaC.x;
  final cy = juliaC.y;
  final bailout2 = bailout * bailout;

  int it = 0;
  while (it < iterations) {
    final nx = zx * zx - zy * zy + cx + p * zPrevX;
    final ny = 2.0 * zx * zy + cy + p * zPrevY;

    zPrevX = zx;
    zPrevY = zy;
    zx = nx;
    zy = ny;

    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterDeltoid(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Matches cpu_formulas.dart (ported from shaders/escape_time_family/polynomial_maps/fractional_and_folded/deltoid_gpu.frag)
  final cx = x;
  final cy = y;
  // Start z at c; starting at 0 makes z=0 a fixed point for this recurrence.
  double zx = cx;
  double zy = cy;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final czx = cx * zx + cy * zy;
    final czy = cy * zx - cx * zy;
    zx = z2x + czx;
    zy = z2y + czy;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterEisenstein(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Matches cpu_formulas.dart (ported from shaders/escape_time_family/polynomial_maps/lattice_wrapped/eisenstein_gpu.frag)
  const sqrt3 = 1.7320508075688772;
  final cx = x;
  final cy = y;
  double zx = 0.0;
  double zy = 0.0;

  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z3x = z2x * zx - z2y * zy + cx;
    final z3y = z2x * zy + z2y * zx + cy;

    final rawMag2 = z3x * z3x + z3y * z3y;
    if (rawMag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: rawMag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final r = (2.0 * z3y) / sqrt3;
    final q = z3x - z3y / sqrt3;
    final rq = (q + 0.5).floorToDouble();
    final rr = (r + 0.5).floorToDouble();

    final lattX = rq + 0.5 * rr;
    final lattY = 0.5 * sqrt3 * rr;
    zx = z3x - lattX;
    zy = z3y - lattY;

    if (zx * zx + zy * zy > bailout2 * 0.25) {
      final m2 = zx * zx + zy * zy;
      final smooth = _smoothEscape(it: it, mag2: m2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

int _fnv1a32(String s) {
  int h = 0x811c9dc5;
  for (final cu in s.codeUnits) {
    h ^= cu;
    h = (h * 0x01000193) & 0xFFFFFFFF;
  }
  return h;
}

int _mix32(int x) {
  x &= 0xFFFFFFFF;
  x ^= (x >> 16);
  x = (x * 0x7feb352d) & 0xFFFFFFFF;
  x ^= (x >> 15);
  x = (x * 0x846ca68b) & 0xFFFFFFFF;
  x ^= (x >> 16);
  return x & 0xFFFFFFFF;
}

double _smoothEscape(
    {required int it, required double mag2, required double bailout}) {
  // Standard continuous potential smoothing.
  // nu = log(log(|z|))/log(2)
  final r = math.sqrt(mag2);
  final nu =
      math.log(math.max(1e-9, math.log(math.max(r, bailout)))) / math.ln2;
  return it + 1.0 - nu;
}

import 'dart:async';
import 'dart:isolate';

import 'cpu_render_isolate.dart';

/// A long-lived isolate for CPU tile rendering.
///
/// Spawning an isolate per tile (Isolate.run) is far too slow on mobile.
/// This worker keeps one isolate alive and processes tile jobs sequentially.
class CpuTileWorker {
  CpuTileWorker._(this._isolate, this._sendPort, this._sub);

  final Isolate _isolate;
  final SendPort _sendPort;
  final StreamSubscription _sub;

  static Future<CpuTileWorker> spawn() async {
    final receive = ReceivePort();
    final handshake = Completer<SendPort>();

    final sub = receive.listen((msg) {
      if (msg is SendPort && !handshake.isCompleted) {
        handshake.complete(msg);
      }
    });

    final isolate = await Isolate.spawn(_entry, receive.sendPort);
    final sendPort = await handshake.future;

    return CpuTileWorker._(isolate, sendPort, sub);
  }

  Future<CpuTileRenderResponse> renderTile(CpuTileRenderRequest req) async {
    final rp = ReceivePort();
    _sendPort.send((req, rp.sendPort));
    final msg = await rp.first;
    rp.close();
    return msg as CpuTileRenderResponse;
  }

  void dispose() {
    _sub.cancel();
    _isolate.kill(priority: Isolate.immediate);
  }
}

void _entry(SendPort mainSendPort) {
  final commands = ReceivePort();
  mainSendPort.send(commands.sendPort);

  commands.listen((msg) {
    final (CpuTileRenderRequest req, SendPort replyTo) = msg as (CpuTileRenderRequest, SendPort);
    final resp = renderCpuTileInIsolate(req);
    replyTo.send(resp);
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/features/renderer/cpu_formulas.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';

void main() {
  group('CPU render viewport mapping', () {
    test('keeps opposite edge pixel centers symmetric around pan', () {
      final left = cpuViewportCoordinateForSample(
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        fullWidth: 4,
        fullHeight: 2,
        x: 0,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );
      final right = cpuViewportCoordinateForSample(
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        fullWidth: 4,
        fullHeight: 2,
        x: 3,
        y: 1,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(left.x + right.x, closeTo(-1.0, 1e-12));
      expect(left.y + right.y, closeTo(0.5, 1e-12));
    });

    test('rejects tile rectangles outside the full viewport before sampling', () {
      const request = CpuTileRenderRequest(
        moduleId: 'mandelbrot',
        panX: 0.0,
        panY: 0.0,
        zoom: 1.0,
        iterations: 32,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        fullWidth: 4,
        fullHeight: 4,
        x0: 3,
        y0: 0,
        w: 2,
        h: 1,
        sampleCount: 1,
      );

      expect(
        () => renderCpuTileInIsolate(request),
        throwsA(
          isA<ArgumentError>().having(
            (error) => error.message,
            'message',
            contains('within the full viewport'),
          ),
        ),
      );
    });

    test('maps a one-pixel frame to the requested pan center', () {
      const request = CpuRenderRequest(
        moduleId: 'mandelbrot',
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        iterations: 32,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        width: 1,
        height: 1,
        sampleCount: 1,
      );

      final frame = renderCpuFrameInIsolate(request);
      final expected = cpuFormulaForModuleId(request.moduleId)(
        request.panX,
        request.panY,
        request.iterations,
        request.bailout,
        Vector2(request.juliaCX, request.juliaCY),
      );

      expect(frame.rgba, hasLength(4));
      expect(frame.rgba[0], expected.$1.clamp(0, 255).round());
      expect(frame.rgba[1], expected.$2.clamp(0, 255).round());
      expect(frame.rgba[2], expected.$3.clamp(0, 255).round());
      expect(frame.rgba[3], 255);
    });
  });
}

